(1290, '_hello-biz_notifications', 'a:2:{s:7:\"timeout\";i:1783883039;s:5:\"value\";s:3807:\"[{\"id\":\"hello-biz-1.2.2\",\"title\":\"1.2.2 - 2026-05-24\",\"description\":\"\\n            <ul>\\n                <li>Fix: CSS improvements for Elementor widgets<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.2.1\",\"title\":\"1.2.1 - 2026-03-16\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Updated theme homepage<\\/li>\\n\\t\\t\\t\\t<li>Tweak: Rebranding updates<\\/li>\\n\\t\\t\\t\\t<li>Tweak: Updated the Import\\/Export flow<\\/li>\\n\\t\\t\\t\\t<li>Fix: Hello Biz banner close button<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.2.0\",\"title\":\"1.2.0 - 2025-09-18\",\"description\":\"\\n            <ul>\\n                <li>New: Added onboarding banners for users installing Hello Biz after installing an Elementor kit<\\/li>\\n\\t\\t\\t\\t<li>New: Added admin bar link to return to theme home from the front end<\\/li>\\n\\t\\t\\t\\t<li>New: Added Hello Biz home link to the Finder<\\/li>\\n\\t\\t\\t\\t<li>Tweak: Refactored behavior of links in the customizer to better reflect the flow<\\/li>\\n\\t\\t\\t\\t<li>Tweak: Unified Theme Settings options and UI across all Hello themes for a more consistent experience<\\/li>\\n\\t\\t\\t\\t<li>Fix: Improved banner display on certain pages for consistency<\\/li>\\n\\t\\t\\t\\t<li>Fix: Show the Theme Builder link on the theme home page and in the menu when Elementor is active<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.1.0\",\"title\":\"1.1.0 - 2025-04-27\",\"description\":\"\\n            <ul>\\n                <li>New: 404 page styling<\\/li>\\n\\t\\t\\t\\t<li>New: Search page styling<\\/li>\\n\\t\\t\\t\\t<li>Fix: Unexpected behavior of settings option \\\"Hide default theme header & footer\\\"<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.7\",\"title\":\"1.0.7 - 2025-04-08\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Improve styling of pages password lock<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.6\",\"title\":\"1.0.6 - 2025-03-30\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Update the theme description<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.5\",\"title\":\"1.0.5 - 2025-03-16\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Update the theme readme file<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.4\",\"title\":\"1.0.4 - 2025-03-02\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Add \\\"changelog\\\" modal to theme settings page<\\/li>\\n                <li>Tweak: Add FAQ section to theme info<\\/li>\\n                <li>Fix: Prevent duplicated Header\\/Footer view in Editor<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.3\",\"title\":\"1.0.3 - 2025-02-11\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Allow Skipping the default Header\\/Footer templates<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.2\",\"title\":\"1.0.2 - 2025-01-22\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Theme URI<\\/li>\\n                <li>Fix: Add missing translation strings<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.1\",\"title\":\"1.0.1 - 2024-12-24\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Improved Gutenberg support<\\/li>\\n                <li>Tweak: Use CSS Logical properties<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.0\",\"title\":\"1.0.0 - 2024-12-11\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Minify starter-content images<\\/li>\\n                <li>Fix: Settings page styling<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-0.0.6\",\"title\":\"0.0.6 - 2024-12-04\",\"description\":\"\\n            <ul>\\n                <li>New: Add starter content<\\/li>\\n           <\\/ul>\"},{\"id\":\"hello-biz-0.0.5\",\"title\":\"0.0.5 - 2024-11-25\",\"description\":\"\\n            <ul>\