(1294, '_elementor_notifications_data', 'a:2:{s:7:\"timeout\";i:1783904467;s:5:\"value\";s:12640:\"[{\"id\":\"angie-super-community\",\"title\":\"Angie Community Library\",\"description\":\"Browse a library of snippets and widgets built by other Angie users, import any of them into your site, without consuming any credits or remix them with a prompt to match your brief. Every snippet is vetted by the Elementor team. You can also submit your own work for the community to discover.\",\"topic\":\"Angie\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-community.png\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-angie-community\\/\",\"readMoreText\":\"Browse library\"},{\"id\":\"4.1-atomic-form\",\"title\":\"Generate Atomic Forms\",\"description\":\"Ask Angie to generate forms for lead generation, contact, bookings, promotions and more. Use the new atomic form elements like date picker, radio button, and file upoad.\",\"topic\":\"Atomic Editor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/41-atomic-form-angie.png\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.1-blog\\/\",\"readMoreText\":\"Learn More\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"elementor-pro\\/elementor-pro.php\"}]]},{\"id\":\"4.1-atomic-form\",\"title\":\"Generate Atomic Forms\",\"description\":\"Ask Angie to generate forms for lead generation, contact, bookings, promotions and more. Use the new atomic form elements like date picker, radio button, and file upoad.\",\"topic\":\"Atomic Editor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/41-atomic-form-angie.png\",\"chipPlan\":\"Pro\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.1-blog\\/\",\"readMoreText\":\"Learn more\",\"cta\":\"Upgrade now\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.1-atomic-form\\/\"},{\"id\":\"cookie-consent-launch\",\"title\":\"Introducing Cookie Consent\",\"description\":\"Add a cookie consent banner to your site in minutes. Scan for cookies, manage scripts based on visitor consent, and customize the banner to match your site, or design it in the Editor with Elementor Popups. Free to get started, with more features in Elementor One.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/cookie-launch.png\",\"chipTags\":[\"New feature\"],\"cta\":\"Get Cookie Consent\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/cookie-consent-in-editor-whats-new\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"cookiez\\/cookiez.php\",\"operator\":\"!=\"}]]},{\"id\":\"angie-super-admin\",\"title\":\"Super Admin Mode\",\"description\":\"Revolutionize your WordPress workflow with Super Admin Mode. Perform root-level WordPress operations through natural language - bulk post and product updates, PHP error diagnosis, and more.\",\"topic\":\"Angie\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-super-admin.png\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-angie-super-admin\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"4.0-default\",\"title\":\"The new default\",\"description\":\"New sites now start with version 4.0 and atomic features enabled by default. Existing sites can choose to manually activate. Nothing happens to your existing layouts and sites.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-default.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"angie-revisions\",\"title\":\"Restore snippets precisely with Revisions\",\"description\":\"Restore any previous version of your snippets to its exact saved state. Each time you revise, Angie preserves a complete snapshot of the snippet\'s code, structure, and configuration. Open version history, select any saved state, and return to it in one click.\",\"topic\":\"Angie\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-notification-revision.png\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-angie-revisions\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"4.0-atomic-forms\",\"title\":\"Atomic Forms\",\"description\":\"Build forms as part of your layout, not separate widgets. Create flexible, multi-column designs, nest elements freely, and maintain full control with the same atomic system and styling logic.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-atomic-form.png\",\"chipPlan\":\"Pro\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"elementor-pro\\/elementor-pro.php\"}]]},{\"id\":\"4.0-atomic-forms\",\"title\":\"Atomic Forms\",\"description\":\"Build forms as part of your layout, not separate widgets. Create flexible, multi-column designs, nest elements freely, and maintain full control with the same atomic system and styling logic.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/3.33-custom-css.png\",\"chipTags\":[\"Atomic Editor\"],\"cta\":\"Upgrade\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-atomic-forms\\/\"},{\"id\":\"angie-cloud-library\",\"title\":\"Introducing Angie Cloud Library\",\"description\":\"Your Angie snippets are now available across every site you manage. Save any asset you build to your account and pull it into a new project in a few clicks, fully editable and ready to adapt. Available to all users with free daily credits.\",\"topic\":\"Angie\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-cloud-library.png\",\"chipTags\":[\"Angie\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-angie-cloud-library\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"4.0-interactions\",\"title\":\"Pro Interactions\",\"description\":\"Create advanced, lightweight motion inside the Editor. Define behavior visually, keep everything system-based, and deliver engaging experiences without bloated scripts or external tools.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-interactions.png\",\"chipPlan\":\"Pro\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"elementor-pro\\/elementor-pro.php\"}]]},{\"id\":\"4.0-interactions\",\"title\":\"Pro Interactions\",\"description\":\"Create advanced, lightweight motion inside the Editor. Define behavior visually, keep everything system-based, and deliver engaging experiences without bloated scripts or external tools.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-interactions.png\",\"chipTags\":[\"Atomic Editor\"],\"cta\":\"Upgrade\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-interactions\\/\"},{\"id\":\"4.0-sync-design-system\",\"title\":\"Sync and share design systems\",\"description\":\"Export and import Variables and Classes between sites, and sync them with v3 Global Styles. Maintain a consistent design system across projects and across versions.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-sync-design-system.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"angie-launch\",\"title\":\"Introducing Angie Code.\",\"description\":\"Create custom Elementor widgets, and snippets for custom site functionality from a simple description. Built natively for WordPress, and Elementor. Preview safely, refine through conversation, and publish when ready.\",\"topic\":\"Angie Code\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-launch.png\",\"chipTags\":[\"New launch\"],\"link\":\"https:\\/\\/go.elementor.com\\/ai-notification-angie-launch\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"partner-program\",\"title\":\"Partner with Elementor. Grow your business.\",\"description\":\"Join to unlock exclusive access, secure visibility, benefit from marketing opportunities, and create additional revenue from the work you have already done. Join for free and start benefiting!\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/notification-partner.png\",\"chipTags\":[\"Partner Program\"],\"cta\":\"Apply now\",\"ctaLink\":\"https:\\/\\/my.elementor.com\\/agency\\/\"},{\"id\":\"manage-launch\",\"title\":\"Introducing Manage\",\"description\":\"Monitor, optimize and maintain all your sites from one centralized dashboard. Track performance, perform bulk updates and detect security risks to stay ahead of issues.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/manage.png\",\"chipTags\":[\"New Launch\"],\"cta\":\"Start free\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/manage\\/whatsnew\"},{\"id\":\"components-3.35\",\"title\":\"Components\",\"description\":\"Build modular, reusable sections that update everywhere and decide how much control to give away to your team or clients.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/components-3-35.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-components-3.35-blog\",\"readMoreText\":\"Learn More\"},{\"id\":\"one-launch\",\"title\":\"Introducing Elementor One\",\"description\":\"The complete website building experience. All the tools to create, optimize, and manage websites, unified under one roof.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/one-launch.png\",\"chipTags\":[\"New Launch\"],\"cta\":\"Explore Elementor One\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/launch-whats-new\"},{\"id\":\"atomic-tabs-3.34\",\"title\":\"Atomic Tabs\",\"description\":\"Nest any type of content inside tab triggers or content panels, unlocking a truly atomic way of design.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/tabs-3.34.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-3.34-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"variables-manager-3.33\",\"title\":\"Variables Manager\",\"description\":\"Centralize and control all your color, typography, and size tokens for consistent, scalable design systems.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/3.33-variables-manager.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-3.33-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"ally-assistant\",\"title\":\"New! Fix accessibility issues with Ally Assistant\",\"description\":\"Scan any page for accessibility issues and fix them in one click. From color contrast to missing alt text, Ally Assistant provides guided steps or AI-powered fixes to make your site more inclusive.\",\"topic\":\"Ally by Elementor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/ally-assistant.png\",\"chipTags\":[\"New Feature\"],\"cta\":\"Scan for free\",\"ctaLink\":\"http:\\/\\/go.elementor.com\\/acc-assistant-launch-whats-new\",\"conditions\":[[{\"type\":\"plugin\",\"operator\":\"!=\",\"plugin\":\"pojo-accessibility\\/pojo-accessibility.php\"}]]},{\"id\":\"image-optimizer-3.19\",\"title\":\"Effortlessly optimize images for a stunning, high-speed website with the Image Optimizer plugin.\",\"description\":\"Image Optimizer perfectly balances between image quality and performance to boost your website.  Resize, compress, and convert images to WebP, for faster loading times and and better user experience.\",\"topic\":\"Image Optimizer Plugin by Elementor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/image-optimizer-3.19.png\",\"chipTags\":[\"New plugin\"],\"cta\":\"Get the Image Optimizer\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/io-notification-wp-dash-learn-more\\/\",\"conditions\":[[{\"type\":\"plugin\",\"operator\":\"!=\",\"plugin\":\"image-optimization\\/image-optimization.php\"}]]},{\"id\":\"5-star-rating-prompt\",\"title\":\"Love the New Features? Let Us Know with 5 Stars!\",\"description\":\"Help spread the word by telling the world what you love about Elementor.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/5-star-rating-prompt.png\",\"cta\":\"Leave a Review\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/wp-dash-notification-five-stars\\/\"},{\"id\":\"site-mailer-introducing\",\"title\":\"Introducing Site Mailer\",\"description\":\"Keep your WordPress emails out of the spam folder with improved deliverability and an easy setup\\u2014no need for an SMTP plugin or complicated configurations.\",\"topic\":\"Site Mailer Plugin by Elementor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/Site-mailer.png\",\"chipTags\":[\"New plugin\"],\"cta\":\"Start Free Trial\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/sm-wp-dash-whatsnew\\/\",\"conditions\":[[{\"type\":\"plugin\",\"operator\":\"!=\",\"plugin\":\"site-mailer\\/site-mailer.php\"}]]}]\";}', 'off'),
(1299, 'elementor_remote_info_feed_data', 'a:3:{i:0;a:5:{s:5:\"title\";s:43:\"Introducing Angie: Agentic AI for WordPress\";s:7:\"excerpt\";s:365:\"Meet Angie, agentic AI purpose-built for WordPress. Angie understands your site, connects to your tools, and takes real actions on your behalf. Its first capability, Angie Code, lets you describe any WordPress feature you can imagine and have it built for you in minutes. Production-ready, fully integrated with your site, and safe to test before it ever goes live.\";s:7:\"created\";i:1774270910;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:142:\"https://elementor.com/blog/introducing-angie-agentic-ai-for-wordpress/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}i:1;a:5:{s:5:\"title\";s:59:\"The atomic foundation of version 4 is ready for real sites!\";s:7:\"excerpt\";s:296:\"The alpha phase is complete. Version 4 is now in beta, and the atomic foundation is ready to be used on real sites! This is the final step before the official release of version 4.0, activating the new features automatically on new sites, and becoming the default editing experience in Elementor.\";s:7:\"created\";i:1770651621;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:113:\"https://elementor.com/blog/editor-4-beta/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}i:2;a:5:{s:5:\"title\";s:79:\"Introducing Elementor 3.33: Variables Manager, Custom CSS, Blend Modes, & more!\";s:7:\"excerpt\";s:340:\"Elementor 3.33 builds on the foundation of Editor V4, continuing our mission to create a faster, more scalable, and more intuitive design experience for Web Creators. With the addition of the Variables Manager, element-level Custom CSS, Background Clipping, and Blend Modes, designers have more creative precision and consistency than ever.\";s:7:\"created\";i:1762944115;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:145:\"https://elementor.com/blog/elementor-333-v4-variables-manager-custom-css/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}}', 'off'),
(1302, '_elementor_v4_promotions', 'a:2:{s:7:\"timeout\";i:1783864869;s:5:\"value\";s:3523:\"[{\"customCss\":{\"title\":\"Custom CSS\",\"content\":\"Add custom CSS to refine and enrich the appearance of any element on your site.\",\"ctaUrl\":\"https:\\/\\/go.elementor.com\\/go-pro-style-custom-css\\/\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/custom_css_promotion.png\"},\"displayConditions\":{\"title\":\"Display conditions\",\"content\":\"Control when and where elements are shown across your site.\",\"ctaUrl\":\"https:\\/\\/go.elementor.com\\/go-pro-display-conditions-modal\\/\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/display_conditions_promotion.png\"},\"attributes\":{\"title\":\"Attributes\",\"content\":\"Add custom attributes when you need deeper customization and better accessibility.\",\"ctaUrl\":\"https:\\/\\/go.elementor.com\\/go-pro-attributes-modal\\/\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/attributes_promotion.png\"},\"Portfolio\":{\"title\":\"Portfolio\",\"content\":\"Upgrade to build dynamic portfolio grids featuring interactive category filtering and engaging hover effects designed to captivate your site visitors.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Portfolio_promotion.png\"},\"Form\":{\"title\":\"Form\",\"content\":\"Upgrade to build advanced forms featuring custom fields, multi-step layouts, automated email notifications, and direct CRM integrations.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Form_promotion.png\"},\"PriceList\":{\"title\":\"Price list\",\"content\":\"Upgrade to present items, descriptions, and pricing within a cohesive structure that aligned perfectly with your site.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Price_list_promotion.png\"},\"PriceTable\":{\"title\":\"Price table\",\"content\":\"Upgrade to build pricing matrices featuring highlighted columns, interactive check mark lists, and integrated action buttons.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Price_table_promotion.png\"},\"LoopGrid\":{\"title\":\"Loop Grid\",\"content\":\"Upgrade to connect custom layouts directly to your site database, seamlessly rendering dynamic content queries that engage your site visitors.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Loop_grid_promotion.png\"},\"CallToAction\":{\"title\":\"Call to Action\",\"content\":\"Upgrade to build Call to Action blocks with image overlays, custom hover animations, and promotional layout control across your site.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/CTA_promotion.png\"},\"Template\":{\"title\":\"Template\",\"content\":\"Upgrade to embed saved templates that sync automatically across your entire site, preserving layout integrity and accelerating your production speed.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Template_promotion.png\"},\"Gallery\":{\"title\":\"Gallery pro\",\"content\":\"Upgrade to build gallery with dynamic categorization and custom layout control across your site.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Gallery_pro_promotion.png\"},\"MediaCarousel\":{\"title\":\"Media carousel\",\"content\":\"Upgrade to build advanced Media Carousel with dynamic video elements into your sliders to better engage your site visitors.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Media_carousel_promotion.png\"},\"LoopCarousel\":{\"title\":\"Loop carousel\",\"content\":\"Upgrade to build advanced Loop Carousel with dynamic posts, custom layouts seamlessly to better engage your site visitors.\",\"image\":\"https:\\/\\/assets.elementor.com\\/packages\\/v1\\/images\\/Loop_carousel_promotion.png\"}}]\";}', 'off'),
