(32, 1, '2026-07-09 07:25:43', '2026-07-09 07:25:43', '<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"yith-wonder\",\"tagName\":\"header\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"align\":\"full\",\"layout\":{\"inherit\":true,\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group alignfull\"><!-- wp:spacer {\"height\":\"40px\"} -->\n<div style=\"height:40px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:group {\"layout\":{\"contentSize\":\"900px\",\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\"><!-- wp:heading {\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"4rem\",\"textAlign\":\"center\"}},\"textColor\":\"primary\"} -->\n<h1 class=\"wp-block-heading has-text-align-center has-primary-color has-text-color\" style=\"font-size:4rem\">Welcome to the Auction</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"textAlign\":\"center\"}},\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-center has-medium-font-size\">Post an item for sale or bid for available items.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {\"height\":\"80px\"} -->\n<div style=\"height:80px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:query {\"queryId\":0,\"query\":{\"perPage\":10,\"pages\":0,\"offset\":0,\"postType\":\"post\",\"order\":\"desc\",\"orderBy\":\"date\",\"author\":\"\",\"search\":\"\",\"exclude\":[],\"sticky\":\"\",\"inherit\":true},\"align\":\"full\",\"layout\":{\"contentSize\":null,\"type\":\"constrained\"}} -->\n<div class=\"wp-block-query alignfull\"><!-- wp:post-template {\"layout\":{\"type\":\"grid\",\"columnCount\":2}} -->\n<!-- wp:cover {\"useFeaturedImage\":true,\"dimRatio\":0,\"overlayColor\":\"primary\",\"isUserOverlayColor\":true,\"minHeight\":100,\"minHeightUnit\":\"%\",\"contentPosition\":\"bottom center\",\"isDark\":false,\"style\":{\"spacing\":{\"padding\":{\"top\":\"70%\",\"right\":\"var:preset|spacing|50\",\"bottom\":\"0px\",\"left\":\"var:preset|spacing|50\"}}}} -->\n<div class=\"wp-block-cover is-light has-custom-content-position is-position-bottom-center\" style=\"padding-top:70%;padding-right:var(--wp--preset--spacing--50);padding-bottom:0px;padding-left:var(--wp--preset--spacing--50);min-height:100%\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-primary-background-color has-background-dim-0 has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"20px\",\"padding\":{\"top\":\"var:custom|xl-spacing\",\"right\":\"var:custom|xl-spacing\",\"bottom\":\"var:custom|xl-spacing\",\"left\":\"var:custom|xl-spacing\"}}},\"backgroundColor\":\"base\",\"layout\":{\"inherit\":true,\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-base-background-color has-background\" style=\"padding-top:var(--wp--custom--xl-spacing);padding-right:var(--wp--custom--xl-spacing);padding-bottom:var(--wp--custom--xl-spacing);padding-left:var(--wp--custom--xl-spacing)\"><!-- wp:post-title {\"isLink\":true,\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"600\",\"lineHeight\":1.3000000000000000444089209850062616169452667236328125},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\",\"fontSize\":\"large\"} /-->\n\n<!-- wp:spacer {\"height\":\"20px\"} -->\n<div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:post-excerpt {\"moreText\":\"READ MORE \\u003cspan aria-hidden=\'true\'\\u003e→\\u003c/span\\u003e\",\"textColor\":\"contrast\",\"fontSize\":\"small\"} /--></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover -->\n<!-- /wp:post-template -->\n\n<!-- wp:spacer {\"height\":\"40px\"} -->\n<div style=\"height:40px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:query-pagination {\"paginationArrow\":\"arrow\",\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<!-- wp:query-pagination-previous {\"label\":\"Previous\",\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n\n<!-- wp:query-pagination-numbers {\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n\n<!-- wp:query-pagination-next {\"label\":\"Next\",\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n<!-- /wp:query-pagination --></div>\n<!-- /wp:query --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"yith-wonder\",\"tagName\":\"footer\"} /-->', 'Blog Home', 'Displays the latest posts as either the site homepage or as the \"Posts page\" as defined under reading settings. If it exists, the Front Page template overrides this template when posts are shown on the homepage.', 'publish', 'closed', 'closed', '', 'home', '', '', '2026-07-09 07:34:14', '2026-07-09 07:34:14', '', 0, 'http://localhost/wordpress/home/', 0, 'wp_template', '', 0),
