pacing|50\",\"bottom\":\"0px\",\"left\":\"var:preset|spacing|50\"}}}} -->\n<div class=\"wp-block-cover is-light has-custom-content-position is-position-bottom-center\" style=\"padding-top:70%;padding-right:var(--wp--preset--spacing--50);padding-bottom:0px;padding-left:var(--wp--preset--spacing--50);min-height:100%\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-primary-background-color has-background-dim-0 has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"20px\",\"padding\":{\"top\":\"var:custom|xl-spacing\",\"right\":\"var:custom|xl-spacing\",\"bottom\":\"var:custom|xl-spacing\",\"left\":\"var:custom|xl-spacing\"}}},\"backgroundColor\":\"base\",\"layout\":{\"inherit\":true,\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-base-background-color has-background\" style=\"padding-top:var(--wp--custom--xl-spacing);padding-right:var(--wp--custom--xl-spacing);padding-bottom:var(--wp--custom--xl-spacing);padding-left:var(--wp--custom--xl-spacing)\"><!-- wp:post-title {\"isLink\":true,\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"600\",\"lineHeight\":1.3000000000000000444089209850062616169452667236328125},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\",\"fontSize\":\"large\"} /-->\n\n<!-- wp:spacer {\"height\":\"20px\"} -->\n<div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:post-excerpt {\"moreText\":\"READ MORE \\u003cspan aria-hidden=\'true\'\\u003e→\\u003c/span\\u003e\",\"textColor\":\"contrast\",\"fontSize\":\"small\"} /--></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover -->\n<!-- /wp:post-template -->\n\n<!-- wp:spacer {\"height\":\"40px\"} -->\n<div style=\"height:40px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:query-pagina