wordpress/refund_returns/\" data-type=\"page\" data-id=\"13\">Refund and Returns Policy</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {\"height\":\"20px\"} -->\n<div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->', 'Footer', '', 'publish', 'closed', 'closed', '', 'footer', '', '', '2026-07-09 07:35:07', '2026-07-09 07:35:07', '', 0, 'http://localhost/wordpress/footer/', 0, 'wp_template_part', '', 0),
