ation {\"paginationArrow\":\"arrow\",\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<!-- wp:query-pagination-previous {\"label\":\"Previous\",\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n\n<!-- wp:query-pagination-numbers {\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n\n<!-- wp:query-pagination-next {\"label\":\"Next\",\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}}} /-->\n<!-- /wp:query-pagination --></div>\n<!-- /wp:query --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"yith-wonder\",\"tagName\":\"footer\"} /-->', 'Blog Home', 'Displays the latest posts as either the site homepage or as the \"Posts page\" as defined under reading settings. If it exists, the Front Page template overrides this template when posts are shown on the homepage.', 'inherit', 'closed', 'closed', '', '32-revision-v1', '', '', '2026-07-09 07:34:14', '2026-07-09 07:34:14', '', 32, 'http://localhost/wordpress/?p=38', 0, 'revision', '', 0),
